module RefModule (
    input sel,
    input [7:0] in0,
    input [7:0] in1,
    output [7:0] out
);

    reg [7:0] unused_mux_out;  // Multiplexer output register

    always @(*) begin
        case (sel)
            1'b0: unused_mux_out = in0;
            1'b1: unused_mux_out = in1;
            default: unused_mux_out = 8'b00000000;  // Default case (should not occur)
        endcase
    end

    assign out = unused_mux_out;

endmodule
